<template>
  <div>
    <el-menu
      router
      :collapse="menuIsCollapse"
      :default-active="currentActiveRoute"
    >
      <img src="@/assets/Spectre_logo_blue.svg" />
      <template v-for="(item, index) in menus" :key="index">
        <el-menu-item :index="item.path">
          <i :class="item.meta.icon" style="font-size: 22px"></i>
          <span>{{ item.name }}</span>
        </el-menu-item>
      </template>
    </el-menu>
  </div>
</template>
    
<script setup>
import menus from "@/router/menu.js";
import { computed, ref, watch } from "vue";
import { useRoute } from "vue-router";
import { useStore } from "vuex";

const route = useRoute();
const store = useStore();

// 当前活动的路由
const currentActiveRoute = ref("");

const menuIsCollapse = computed(() => {
  return store.state.menuIsCollapse;
});

// 监听器：监听路由的变化，将新路由的路径赋值给currentActiveRoute
// 而将新路由的路径赋值给currentActiveRoute又绑定到了el-menu的default-active属性（默认激活菜单的index）
watch(route, (newVal) => {
  currentActiveRoute.value = newVal.path;
});
</script>
    
<style scoped>
a {
  text-decoration: none;
}
.el-menu {
  height: 100vh;
  overflow: hidden;
}
.el-menu img {
  width: 130px;
  padding: 12px 30px;
}
.el-menu-item {
  letter-spacing: 8px;
  text-indent: 5px;
  font-size: 16px;
  text-shadow: 1.5px 1.5px 1px #ccc;
  transition: 0.3s;
}
.el-menu-item.is-active {
  background: var(--el-color-primary-light-9);
  border-right: 6px solid var(--el-menu-active-color);
  margin-right: -1px;
}
.el-menu-item:hover {
  background: var(--el-color-primary-light-8);
}
.el-menu-item:active {
  background: var(--el-color-primary-light-7);
  transform: scale(0.9);
}
</style>